using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.StaticFiles;
using System.IO;

namespace FileServerApp.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    public class FilesController : ControllerBase
    {
        private readonly string _uploadsFolder;
        private readonly IContentTypeProvider _contentTypeProvider;

        public FilesController(IWebHostEnvironment environment, IContentTypeProvider contentTypeProvider)
        {
            _uploadsFolder = Path.Combine(environment.ContentRootPath, "uploads");
            _contentTypeProvider = contentTypeProvider;
            
            if (!Directory.Exists(_uploadsFolder))
            {
                Directory.CreateDirectory(_uploadsFolder);
            }
        }

        [HttpGet("{filename}")]
        public IActionResult GetFile(string filename)
        {
            if (string.IsNullOrWhiteSpace(filename))
            {
                return BadRequest("Filename is required");
            }

            if (filename.Contains("..") || 
                filename.Contains("/") || 
                filename.Contains("\\") ||
                Path.IsPathRooted(filename))
            {
                return BadRequest("Invalid filename");
            }

            var requestedFilePath = Path.Combine(_uploadsFolder, filename);
            
            var fullRequestedPath = Path.GetFullPath(requestedFilePath);
            var fullUploadsPath = Path.GetFullPath(_uploadsFolder);

            if (!fullRequestedPath.StartsWith(fullUploadsPath + Path.DirectorySeparatorChar) &&
                !fullRequestedPath.Equals(fullUploadsPath))
            {
                return BadRequest("Access denied");
            }

            if (!System.IO.File.Exists(fullRequestedPath))
            {
                return NotFound("File not found");
            }

            if (!_contentTypeProvider.TryGetContentType(fullRequestedPath, out var contentType))
            {
                contentType = "application/octet-stream";
            }

            var fileStream = new FileStream(fullRequestedPath, FileMode.Open, FileAccess.Read, FileShare.Read);
            return File(fileStream, contentType, filename);
        }
    }
}